#nullable enable // autogenerated

using System;
using PVZEngine;
using PVZEngine.Base;

namespace MVZ2.Metas
{
    public static class AlmanacVariableFunctions
    {
        public static object? EvaluateFunctions(AlmanacVariableContext context, string name, object?[] args)
        {
            switch (name)
            {
                case "global":
                    return global(context, args);
                case "local":
                    return local(context, args);
                case "property":
                    return property(context, args);
            }
            return null;
        }
        public static object? global(AlmanacVariableContext context, object?[] args)
        {
            if (context == null)
                throw new Exception("No AlmanacVariableContext provided.");
            if (args.Length == 1 && args[0] is string idStr)
            {
                var id = NamespaceID.Parse(idStr, context.main.BuiltinNamespace);
                var variable = context.main.ResourceManager.GetAlmanacGlobalVariable(id);
                if (variable == null)
                    throw new Exception($"Cannot find global almanac variable {idStr}");


                if (!context.globalCallStack.Add(id))
                    throw new Exception($"Cyclic dependency detected: {idStr}");
                try
                {
                    return variable.GetVariableValue(context);
                }
                finally
                {
                    context.globalCallStack.Remove(id);
                }
            }
            throw new Exception("Invalid global() usage");
        }
        public static object? local(AlmanacVariableContext context, object?[] args)
        {
            if (context == null)
                throw new Exception("No AlmanacVariableContext provided.");
            if (args.Length == 1 && args[0] is string idStr)
            {
                var variable = context.currentAlmanacEntry.GetLocalVariable(idStr);
                if (variable == null)
                    throw new Exception($"Cannot find local almanac variable {idStr} in entry {context.currentAlmanacEntry.name}");


                if (!context.localCallStack.Add(idStr))
                    throw new Exception($"Cyclic dependency detected: {idStr}");
                try
                {
                    return variable.GetVariableValue(context);
                }
                finally
                {
                    context.localCallStack.Remove(idStr);
                }
            }
            throw new Exception("Invalid local() usage");
        }
        public static object? property(AlmanacVariableContext context, object?[] args)
        {
            if (context == null)
                throw new Exception("No AlmanacVariableContext provided.");
            var arg0 = args[0];
            string? key = null;
            if (arg0 != null)
            {
                key = arg0.ToString();
                var propertyKey = PropertyMapper.ConvertFromName(key);
                if (propertyKey.IsValid())
                {

                    var definitionId = context.currentDefinitionID;
                    var definitionType = context.currentDefinitionType;

                    if (args.Length >= 2)
                    {
                        var arg1 = args[1];
                        if (arg1 is NamespaceID nid)
                            definitionId = nid;
                        else if (arg1 != null)
                            definitionId = NamespaceID.Parse(arg1.ToString(), context.main.BuiltinNamespace);
                        else
                            definitionId = null;
                    }
                    if (args.Length >= 3)
                    {
                        var arg2 = args[2];
                        if (arg2 != null)
                            definitionType = arg2.ToString();
                        else
                            definitionType = string.Empty;
                    }
                    var definition = context.main.Game.GetDefinition<Definition>(definitionType, definitionId);
                    if (definition == null)
                        throw new Exception($"Cannot find definition {definitionId} of type {definitionType} in variable of almanac entry {context.currentAlmanacEntry.name}.");

                    return definition.GetPropertyObject(propertyKey);
                }
            }
            throw new Exception($"Cannot find property of key {key} in variable of almanac entry {context.currentAlmanacEntry.name}.");
        }
    }
}
